<?php
 namespace WPAICG\Vector\ManagerMethods; use WP_Error; if (!defined('ABSPATH')) { exit; } function upsert_vectors_logic(string $provider, string $index_name, array $vectors, array $provider_config): array|WP_Error { $strategy = get_connected_strategy_logic($provider, $provider_config); if (is_wp_error($strategy)) { return $strategy; } return $strategy->upsert_vectors($index_name, $vectors); }